    /// <summary>
    /// Gets the union variants (ref strings) for a union type.
    /// </summary>
    /// <param name="refString">The reference to the union type.</param>
    /// <param name="currentNsid">The current NSID context for resolving local refs.</param>
    /// <returns>List of variant refs, or null if not a union type.</returns>
    public List<string>? GetUnionVariants(string refString, string currentNsid)
    {
        var fullRef = ResolveLocalRef(refString, currentNsid);
        var typeInfo = Lookup(fullRef);

        if (typeInfo?.Kind != LexiconTypeKind.Union)
        {
            return null;
        }

        return typeInfo.UnionRefs;
    }

    /// <summary>
    /// Gets all union variants with their resolved C# type names and discriminators.
    /// </summary>
    /// <param name="refString">The reference to the union type.</param>
    /// <param name="currentNsid">The current NSID context for resolving local refs.</param>
    /// <returns>List of (CSharpTypeName, Discriminator) tuples for each variant.</returns>
    public List<(string CSharpType, string Discriminator)>? GetUnionVariantDetails(string refString, string currentNsid)
    {
        var variants = GetUnionVariants(refString, currentNsid);
        if (variants == null)
        {
            return null;
        }

        var result = new List<(string, string)>();
        var unionFullRef = ResolveLocalRef(refString, currentNsid);
        var unionTypeInfo = Lookup(unionFullRef);

        foreach (var variantRef in variants)
        {
            var variantFullRef = ResolveLocalRef(variantRef, unionTypeInfo?.Nsid ?? currentNsid);
            var variantTypeInfo = Lookup(variantFullRef);

            var csharpType = ResolveToCSharpType(variantRef, unionTypeInfo?.Nsid ?? currentNsid);
            var discriminator = variantTypeInfo?.FullRef ?? variantFullRef;

            result.Add((csharpType, discriminator));
        }

        return result;
    }

    /// <summary>
    /// Checks if a type has any union-typed properties.
    /// </summary>
    /// <param name="refString">The reference to check.</param>
    /// <param name="currentNsid">The current NSID context.</param>
    /// <returns>True if the type has union properties.</returns>
    public bool HasUnionProperties(string refString, string currentNsid)
    {
        var fullRef = ResolveLocalRef(refString, currentNsid);
        var typeInfo = Lookup(fullRef);

        if (typeInfo?.Definition?.Properties == null)
        {
            return false;
        }

        foreach (var prop in typeInfo.Definition.Properties.Values)
        {
            if (prop.Type == "union")
            {
                return true;
            }

            if (prop.Type == "array" && prop.Items?.Type == "union")
            {
                return true;
            }

            if (!string.IsNullOrEmpty(prop.Ref))
            {
                var refKind = GetRefKind(prop.Ref!, typeInfo.Nsid);
                if (refKind == LexiconTypeKind.Union)
                {
                    return true;
                }
            }
        }

        return false;
    }

